  phrases: [{ hi: "मेट्रो स्टेशन कहाँ है?", it: "Dov’è la stazione metro?", ipa: "metro steshan kahaan hai?" }, { hi: "सीधा जाइए।", it: "Vada dritto.", ipa: "siidhaa jaaiye" }, { hi: "दाएँ मुड़िए।", it: "Giri a destra.", ipa: "daaen mudiye" }, { hi: "बाएँ मुड़िए।", it: "Giri a sinistra.", ipa: "baaen mudiye" }, { hi: "क्या यह पास है?", it: "È vicino?", ipa: "kyaa yah paas hai?" }, { hi: "बहुत दूर है?", it: "È molto lontano?", ipa: "bahut duur hai?" }],
  grammar: "जाइए e मुड़िए sono forme cortesi per “vada” e “giri”. Le indicazioni in hindi possono essere molto brevi: सीधा, फिर दाएँ significa “dritto, poi a destra”. Quando non capisci, puoi chiedere di ripetere con कृपया फिर से बोलिए।",
