  focus: "Oggi impari a spiegare problemi pratici: ritardi, oggetti persi, stanze non pronte e servizi che non funzionano. Sei in viaggio tra Agra e Delhi.",
  vocab: [{ hi: "देरी", it: "ritardo", ipa: "derii" }, { hi: "समस्या", it: "problema", ipa: "samasyaa" }, { hi: "रद्द", it: "cancellato", ipa: "radd" }, { hi: "बंद", it: "chiuso / spento", ipa: "band" }, { hi: "खुला", it: "aperto", ipa: "khulaa" }, { hi: "टूटा", it: "rotto", ipa: "tuutaa" }, { hi: "खराब", it: "guasto / cattivo", ipa: "kharaab" }, { hi: "गुम", it: "smarrito", ipa: "gum" }, { hi: "मिलना", it: "trovare / ricevere", ipa: "milnaa" }, { hi: "शिकायत", it: "reclamo", ipa: "shikaayat" }],
  phrases: [{ hi: "ट्रेन में देरी है।", it: "Il treno è in ritardo.", ipa: "tren men derii hai" }, { hi: "मेरी बुकिंग नहीं मिल रही।", it: "Non trovano la mia prenotazione.", ipa: "merii buking nahìn mil rahii" }, { hi: "कमरा तैयार नहीं है।", it: "La stanza non è pronta.", ipa: "kamraa taiyaar nahìn hai" }, { hi: "एसी खराब है।", it: "L’aria condizionata non funziona.", ipa: "e-sii kharaab hai" }, { hi: "दरवाज़ा बंद है।", it: "La porta è chiusa.", ipa: "darvaazaa band hai" }, { hi: "मुझे शिकायत करनी है।", it: "Voglio fare un reclamo.", ipa: "mujhe shikaayat karnii hai" }],
  grammar: "नहीं rende negativa la frase e di solito va prima del verbo o dell’espressione finale. तैयार नहीं है significa “non è pronto”; मिल नहीं रहा o नहीं मिल रहा significa “non si trova”. Impara queste frasi come blocchi per risolvere problemi rapidamente.",
  practice: ["Di’ che il treno è in ritardo.", "Spiega che la stanza non è pronta.", "Di’ che l’aria condizionata è guasta.", "Chiedi aiuto per una prenotazione non trovata.", "Crea una frase con समस्या e una con शिकायत."]
