  phrases: [{ hi: "मुझे मदद चाहिए।", it: "Ho bisogno di aiuto.", ipa: "mujhe madad chaahiye" }, { hi: "मुझे स्टेशन जाना है।", it: "Devo andare alla stazione.", ipa: "mujhe steshan jaanaa hai" }, { hi: "यह कितने का है?", it: "Quanto costa questo?", ipa: "yah kitne kaa hai?" }, { hi: "कृपया धीरे बोलिए।", it: "Per favore, parli lentamente.", ipa: "kripyaa dhiire boliye" }, { hi: "मुझे समझ नहीं आया।", it: "Non ho capito.", ipa: "mujhe samajh nahìn aayaa" }, { hi: "धन्यवाद, बहुत मदद मिली।", it: "Grazie, è stato molto utile.", ipa: "dhanyavaad, bahut madad milii" }],
